// Expected payload from n8n-dispatch
// { run_id, enforced_query, max_results, scope, metro, role_focus, ... }
const b = $json.body ?? $json;
const run_id = b.run_id || b.runId || b.runID;
const query = b.enforced_query || b.query || b.enforcedQuery;
const max_results = Number(b.max_results ?? b.maxResults ?? 20);
if (!run_id || !query) {
  return [{ json: { ok:false, error:{code:'MISSING_FIELDS', message:'run_id and enforced_query are required'}, run_id: run_id ?? null, query: query ?? null, max_results } }];
}
return [{ json: { ok:true, run_id, query, max_results: Math.max(1, Math.min(20, max_results)), scope: b.scope ?? null, metro: b.metro ?? null, role_focus: b.role_focus ?? null } }];

// Build compact context for LLM from Firecrawl search response
// Firecrawl /v1/search typically returns { success, data: [ { title, url, description, ... } ] }
const run_id = $node['Normalize Input'].json.run_id;
const query = $node['Normalize Input'].json.query;
const max_results = $node['Normalize Input'].json.max_results ?? 10;
const r = $json;
const items = (r && (r.data || r.results || r.items)) || [];
const arr = Array.isArray(items) ? items : [];

const top = arr.slice(0, max_results).map((it, i) => {
  const title = it.title || it.name || it.pageTitle || null;
  const url = it.url || it.link || it.source_url || null;
  const snippet = it.description || it.snippet || it.text || it.summary || null;
  return `${i+1}. ${title ?? ''}\nURL: ${url ?? ''}\nSnippet: ${snippet ?? ''}`.trim();
});

const search_context = `Query: ${query}\n\nResults:\n${top.join('\n\n')}`;
return [{ json: { run_id, query, search_context, raw_firecrawl: r } }];

