let txt = $json?.choices?.[0]?.message?.content ?? '';
txt = String(txt).trim();
let parsed;
try { parsed = JSON.parse(txt); } catch(e) {
  const m = txt.match(/\[[\s\S]*\]/);
  if (m) parsed = JSON.parse(m[0]); else parsed = [];
}
const people = Array.isArray(parsed) ? parsed : (parsed.people || []);
const run_id = $node['Normalize Input'].json.run_id;
const cleaned = people.slice(0, $node['Normalize Input'].json.max_results).map(p => ({
  name: p.name ?? null,
  title: p.title ?? null,
  organization_name: p.organization_name ?? p.organization ?? null,
  email: p.email ?? null,
  phone: p.phone ?? null,
  source_url: p.source_url ?? p.url ?? null,
  confidence: (typeof p.confidence === 'number') ? p.confidence : null,
  evidence: p.evidence ?? null,
}));
return [{ json: { run_id, status:'completed', results: cleaned } }];
